"""meter.py -- aggregate metered usage events into fixed-size time windows.

Windows are half-open: window i covers timestamps [epoch + i*width, epoch + (i+1)*width).
Timestamps are integer seconds. `width` is a positive integer number of seconds.
Events before `epoch` are out of range and are ignored by bucketize().
"""

def _check_int(name, v):
    if not isinstance(v, int) or isinstance(v, bool):
        raise TypeError(name + " must be an int")
    return v

def validate_events(events):
    """Return events sorted by ts, raising on malformed entries."""
    out = []
    for ev in events:
        if "ts" not in ev or "units" not in ev:
            raise ValueError("event needs ts and units")
        _check_int("ts", ev["ts"])
        out.append({"ts": ev["ts"], "units": ev["units"]})
    out.sort(key=lambda e: e["ts"])
    return out

def bucketize(events, epoch, width):
    """Map window index -> total units. Events with ts < epoch are ignored.
    Empty windows are omitted from the result."""
    if width <= 0:
        raise ValueError("width must be positive")
    buckets = {}
    for ev in validate_events(events):
        if ev["ts"] < epoch:
            continue
        i = window_index(ev["ts"], epoch, width)
        buckets[i] = buckets.get(i, 0) + ev["units"]
    return buckets

def merge_buckets(a, b):
    """Combine two bucket dicts by summing per-window totals."""
    out = dict(a)
    for k, v in b.items():
        out[k] = out.get(k, 0) + v
    return out

def coverage(buckets):
    """Number of distinct non-empty windows in a bucket dict."""
    return len([k for k, v in buckets.items() if v != 0])

def span_bounds(epoch, width, i, j):
    """Half-open bounds covering windows i..j inclusive (i <= j)."""
    if j < i:
        raise ValueError("j must be >= i")
    lo, _ = window_range(epoch, width, i)
    _, hi = window_range(epoch, width, j)
    return (lo, hi)

def busiest(buckets, k):
    """The k window indices with the largest totals, ties broken by index."""
    ordered = sorted(buckets.items(), key=lambda kv: (-kv[1], kv[0]))
    return [idx for idx, _ in ordered[:k]]

def format_report(buckets, epoch, width):
    """Human-readable per-window report using window_range for the bounds."""
    lines = []
    for i in sorted(buckets):
        lo, hi = window_range(epoch, width, i)
        lines.append("[{}, {}): {}".format(lo, hi, buckets[i]))
    return "\n".join(lines)

class Meter:
    """Stateful convenience wrapper around the module functions.

    A Meter collects events and defers all arithmetic to the module-level
    functions, so any windowing bug surfaces identically here and there.
    """
    def __init__(self, epoch, width):
        self.epoch = _check_int("epoch", epoch)
        self.width = _check_int("width", width)
        if width <= 0:
