        self._events = []
    def add(self, ts, units):
        """Record one usage event; returns self for chaining."""
        self._events.append({"ts": ts, "units": units})
        return self
    def extend(self, events):
        """Record many events at once."""
        for ev in events:
            self.add(ev["ts"], ev["units"])
        return self
    def reset(self):
        """Drop all recorded events."""
        self._events = []
        return self
    def buckets(self):
