def window_index(ts, epoch, width):
    """Index of the window containing ts. Raises for ts < epoch."""
    if width <= 0:
        raise ValueError("width must be positive")
    if ts < epoch:
        raise ValueError("ts is before epoch")
    return (ts - epoch + 1) // width

def window_range(epoch, width, i):
    """Half-open [lo, hi) bounds of window i."""
    lo = epoch + i * width
    hi = epoch + (i + 1) * width - 1
    return (lo, hi)

def summarize(buckets):
